import{_ as e,o as a,c as l,a3 as r}from"./chunks/framework.F5zohdGN.js";const f=JSON.parse('{"title":"Hi！这里是 叹号 Bot 有关的内容哦","description":"","frontmatter":{"gitAuthor":"Z User","gitDate":"2026-05-15 05:52:20 +0000","gitHash":"299382009e9ab412b54cce9535f709d249629a72"},"headers":[],"relativePath":"bots/bots.md","filePath":"bots/bots.md"}'),o={name:"bots/bots.md"};function d(n,t,i,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="hi-这里是-叹号-bot-有关的内容哦" tabindex="-1">Hi！这里是 叹号 Bot 有关的内容哦 <a class="header-anchor" href="#hi-这里是-叹号-bot-有关的内容哦" aria-label="Permalink to &quot;Hi！这里是 叹号 Bot 有关的内容哦&quot;">​</a></h1><h2 id="我们管理的机器人" tabindex="-1">我们管理的机器人 <a class="header-anchor" href="#我们管理的机器人" aria-label="Permalink to &quot;我们管理的机器人&quot;">​</a></h2><h3 id="onebot-平台" tabindex="-1">OneBot 平台 <a class="header-anchor" href="#onebot-平台" aria-label="Permalink to &quot;OneBot 平台&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Bot名称</th><th style="text-align:left;">描述</th><th style="text-align:left;">指令列表</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Lar（生产环境）</strong></td><td style="text-align:left;">含 AI 对话功能</td><td style="text-align:left;"><a href="./larbot-commands.html">Lar Bot 指令列表</a></td></tr><tr><td style="text-align:left;"><strong>句号大帝 （生产环境）</strong></td><td style="text-align:left;">不含 AI 对话功能</td><td style="text-align:left;"><a href="./thbot-commands.html">叹号 Bot 指令列表</a></td></tr><tr><td style="text-align:left;"><strong>问号大帝 （备用）</strong></td><td style="text-align:left;">当其他机器人封号时，顶替其位置</td><td style="text-align:left;">-</td></tr><tr><td style="text-align:left;"><strong>逗号大帝（备用）</strong></td><td style="text-align:left;">当 other 机器人封号时，顶替其位置</td><td style="text-align:left;">-</td></tr></tbody></table><h3 id="其他平台" tabindex="-1">其他平台 <a class="header-anchor" href="#其他平台" aria-label="Permalink to &quot;其他平台&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Bot名称</th><th style="text-align:left;">平台</th><th style="text-align:left;">备注</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>tbot</strong></td><td style="text-align:left;">tg</td><td style="text-align:left;">含 AI 对话功能。<a href="./larbot-commands.html">指令列表点我</a></td></tr><tr><td style="text-align:left;"><strong>叹号 Bot</strong></td><td style="text-align:left;">qq</td><td style="text-align:left;">开发中，暂不可用</td></tr><tr><td style="text-align:left;"><strong>Nova</strong></td><td style="text-align:left;">qq</td><td style="text-align:left;">开发中，暂不可用</td></tr><tr><td style="text-align:left;"><strong>叹号 Bot</strong></td><td style="text-align:left;">mail</td><td style="text-align:left;"><a href="mailto:3856150351@qq.com" target="_blank" rel="noreferrer">3856150351@qq.com</a> ，有很强的延迟，不建议日常使用。<a href="./thbot-commands.html">指令列表点我</a></td></tr></tbody></table><h2 id="更新日志" tabindex="-1">更新日志 <a class="header-anchor" href="#更新日志" aria-label="Permalink to &quot;更新日志&quot;">​</a></h2><p>请见 <a href="./bots-updates.html">Bot 更新日志</a></p><hr><h1 id="⚠️-机器人使用规范" tabindex="-1">⚠️ 机器人使用规范 <a class="header-anchor" href="#⚠️-机器人使用规范" aria-label="Permalink to &quot;⚠️ 机器人使用规范&quot;">​</a></h1><p>在使用叹号旗下机器人之前，请务必仔细阅读并遵守以下规范。违反规范可能会导致机器人服务被限制或终止。</p><h2 id="🚫-禁止行为" tabindex="-1">🚫 禁止行为 <a class="header-anchor" href="#🚫-禁止行为" aria-label="Permalink to &quot;🚫 禁止行为&quot;">​</a></h2><h3 id="_1-禁止随意拉群" tabindex="-1">1. 禁止随意拉群 <a class="header-anchor" href="#_1-禁止随意拉群" aria-label="Permalink to &quot;1. 禁止随意拉群&quot;">​</a></h3><p><strong>未经授权，禁止将机器人拉入任何群聊。</strong></p><ul><li>机器人仅供授权群聊使用</li><li>如需在群聊中使用机器人，请提前联系管理员申请</li><li>未经授权拉群可能会导致机器人自动退出，并记录违规行为</li></ul><div class="danger custom-block"><p class="custom-block-title">违规后果</p><ul><li>首次违规：机器人自动退出群聊，并收到警告</li><li>多次违规：可能会被列入黑名单，禁止使用所有机器人服务</li></ul></div><h3 id="联系方式" tabindex="-1">联系方式 <a class="header-anchor" href="#联系方式" aria-label="Permalink to &quot;联系方式&quot;">​</a></h3><ul><li><strong>QQ 群</strong>：<a href="https://qm.qq.com/q/AtZk7q0y88" target="_blank" rel="noreferrer">1065333145</a></li><li><strong>QQ</strong>: 3856150351</li></ul><h2 id="📋-规范总结" tabindex="-1">📋 规范总结 <a class="header-anchor" href="#📋-规范总结" aria-label="Permalink to &quot;📋 规范总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>行为</th><th style="text-align:center;">是否允许</th><th>说明</th></tr></thead><tbody><tr><td>随意拉群</td><td style="text-align:center;">❌</td><td>需提前申请</td></tr><tr><td>正常使用指令</td><td style="text-align:center;">✅</td><td>欢迎使用</td></tr><tr><td>申请后拉群</td><td style="text-align:center;">✅</td><td>需审核通过</td></tr></tbody></table><hr><p>感谢您的理解与配合，让我们共同维护良好的使用环境！ 💙</p>',22)])])}const c=e(o,[["render",d]]);export{f as __pageData,c as default};
